import React from "react";

const Home = () => {
  return (
    <div className="container my-5 text-center">
      <h1 className="mb-4">Welcome to MealPlanner</h1>
      <p className="mb-5">Plan your meals, stay healthy, and reach your goals!</p>

      {/* Banner Image */}
      <div className="home-banner mb-5">
        <img
          src="https://img.freepik.com/free-vector/cartoon-meal-planner_52683-83670.jpg?semt=ais_country_boost&w=740"
          alt="Healthy Meals"
          className="img-fluid rounded shadow"
        />
      </div>

      <div>
        <h2>Get Started Today</h2>
        <p>Create your personalized meal plan and track your nutrition easily.</p>
      </div>
    </div>
  );
};

export default Home;
